// Improved adaptive sort using slice manipulation and pre-checks for sorted data
pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    let len = arr.len();
    if len < 2 { return; }

    // Check for sorted sequences to enable O(N) best case
    // Short-circuiting means O(1) cost for random data
    if len >= 32 {
        let mut asc = true;
        let mut desc = true;
        for w in arr.windows(2) {
            if w[0] > w[1] { asc = false; }
            if w[0] < w[1] { desc = false; }
            if !asc && !desc { break; }
        }
        if asc { return; }
        if desc { arr.reverse(); return; }
    }

    if len < 16 {
        for i in 1..len {
            let mut j = i;
            while j > 0 && arr[j - 1] > arr[j] {
                arr.swap(j, j - 1);
                j -= 1;
            }
        }
        return;
    }

    let mid = len / 2;
    // Median-of-three pivot selection
    if arr[mid] < arr[0] { arr.swap(mid, 0); }
    if arr[len - 1] < arr[0] { arr.swap(len - 1, 0); }
    if arr[len - 1] < arr[mid] { arr.swap(len - 1, mid); }

    arr.swap(mid, len - 1);
    let pivot = arr[len - 1].clone();

    let mut i = 0;
    for j in 0..len - 1 {
        if arr[j] <= pivot {
            arr.swap(i, j);
            i += 1;
        }
    }
    arr.swap(i, len - 1);

    let (left, right) = arr.split_at_mut(i);
    adaptive_sort(left);
    adaptive_sort(&mut right[1..]);
}
